code = """import json, re, pandas as pd

# load clinical alive BRCA (using icd_10=C50.9 per dataset)
path_clin = var_call_kFIUW2EZiMTdhoEUgKuuXr6n
with open(path_clin, 'r') as f:
    clin = json.load(f)

df_clin = pd.DataFrame(clin)
# extract TCGA barcode from patient_description
pat = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')
df_clin['ParticipantBarcode'] = df_clin['patient_description'].str.extract(pat)[0]
# keep needed
alive_brca = df_clin[['ParticipantBarcode','histological_type']].dropna()

# load CDH1 mutated participants
path_mut = var_call_ERI7Gzwr599J0DiHr0qTt2Os
with open(path_mut, 'r') as f:
    muts = json.load(f)
df_mut = pd.DataFrame(muts).dropna()
df_mut = df_mut[['ParticipantBarcode']].drop_duplicates()
df_mut['CDH1_mut'] = 1

# merge
m = alive_brca.merge(df_mut, on='ParticipantBarcode', how='left')
m['CDH1_mut'] = m['CDH1_mut'].fillna(0).astype(int)

# compute per histological_type
grp = m.groupby('histological_type', dropna=False).agg(total_alive=('ParticipantBarcode','nunique'), mutated=('CDH1_mut','sum'))
# CDH1_mut sum counts participants possibly multiple rows; ensure unique participants mutated per histology
# Recompute mutated unique per histology:
mut_unique = m[m['CDH1_mut']==1].groupby('histological_type')['ParticipantBarcode'].nunique()
grp['mutated'] = mut_unique
grp['mutated'] = grp['mutated'].fillna(0).astype(int)
grp['pct_mutated'] = (grp['mutated'] / grp['total_alive'] * 100).round(2)

# top 3 by pct, tie-breaker by mutated then total
res = grp.sort_values(['pct_mutated','mutated','total_alive'], ascending=[False,False,False]).head(3).reset_index()
res_list = res.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(res_list))"""

